"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { LayoutDashboard, Package, Users, Settings, Plus } from "lucide-react";
import { cn } from "@/lib/utils";

const tabs = [
  { href: "/", label: "Home", icon: LayoutDashboard },
  { href: "/stock", label: "Stock", icon: Package },
  { href: "/parties", label: "Parties", icon: Users },
  { href: "/settings", label: "Settings", icon: Settings },
];

interface BottomTabBarProps {
  onFabPress?: () => void;
}

export function BottomTabBar({ onFabPress }: BottomTabBarProps) {
  const pathname = usePathname();

  return (
    <nav
      className="flex items-center justify-around border-t border-[var(--border-default)] bg-[var(--bg-surface)] relative"
      style={{
        height: "var(--tabbar-height)",
        paddingBottom: "env(safe-area-inset-bottom)",
      }}
    >
      {tabs.slice(0, 2).map(({ href, label, icon: Icon }) => (
        <TabItem key={href} href={href} label={label} Icon={Icon} active={pathname === href} />
      ))}

      {/* FAB — center */}
      <div className="flex flex-col items-center" style={{ marginTop: -16 }}>
        <button
          onClick={onFabPress}
          className="flex items-center justify-center rounded-full bg-[var(--brand-ui)] text-white shadow-[var(--shadow-2)] active:bg-[var(--brand-ui-press)] transition-colors"
          style={{ width: "var(--fab-size)", height: "var(--fab-size)" }}
          aria-label="Add Inward"
        >
          <Plus size={22} strokeWidth={2.5} />
        </button>
      </div>

      {tabs.slice(2).map(({ href, label, icon: Icon }) => (
        <TabItem key={href} href={href} label={label} Icon={Icon} active={pathname === href} />
      ))}
    </nav>
  );
}

function TabItem({
  href,
  label,
  Icon,
  active,
}: {
  href: string;
  label: string;
  Icon: React.ElementType;
  active: boolean;
}) {
  return (
    <Link
      href={href}
      className="flex flex-col items-center gap-0.5 min-w-[48px] py-1"
    >
      <Icon
        size={20}
        className={cn(
          active ? "text-[var(--brand-ui)]" : "text-[var(--text-tertiary)]"
        )}
      />
      <span
        className={cn(
          "text-[10px]",
          active
            ? "font-semibold text-[var(--brand-ui)]"
            : "text-[var(--text-tertiary)]"
        )}
      >
        {label}
      </span>
    </Link>
  );
}
