"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { LayoutDashboard, Package, Users, Settings } from "lucide-react";
import { cn } from "@/lib/utils";

const navGroups = [
  {
    label: "Operations",
    items: [
      { href: "/", label: "Home", icon: LayoutDashboard },
      { href: "/stock", label: "Stock", icon: Package },
      { href: "/parties", label: "Parties", icon: Users },
    ],
  },
  {
    label: "System",
    items: [{ href: "/settings", label: "Settings", icon: Settings }],
  },
];

export function SideNav() {
  const pathname = usePathname();

  return (
    <nav
      className="flex flex-col border-r border-[var(--border-default)] bg-[var(--bg-subtle)] overflow-y-auto"
      style={{ width: "var(--sidenav-width)" }}
    >
      <div className="flex-1 py-4 space-y-6">
        {navGroups.map((group) => (
          <div key={group.label}>
            <p className="px-4 mb-2 text-[9px] font-mono uppercase tracking-[0.1em] text-[var(--text-tertiary)]">
              {group.label}
            </p>
            {group.items.map(({ href, label, icon: Icon }) => {
              const isActive = pathname === href;
              return (
                <Link
                  key={href}
                  href={href}
                  className={cn(
                    "flex items-center gap-3 mx-2 px-3 py-2 rounded-[var(--radius-md)] text-[14px] font-medium transition-colors",
                    "duration-[var(--duration-fast)]",
                    isActive
                      ? "bg-[var(--brand-ui)] text-white"
                      : "text-[var(--text-secondary)] hover:bg-[var(--bg-inset)] hover:text-[var(--text-primary)]"
                  )}
                >
                  <Icon size={16} />
                  {label}
                </Link>
              );
            })}
          </div>
        ))}
      </div>
    </nav>
  );
}
