"use client";

import { Badge } from "@/components/ui/Badge";
import { Button } from "@/components/ui/Button";
import { Plus } from "lucide-react";
import Image from "next/image";

interface TopBarProps {
  warehouseName?: string;
  isOnline?: boolean;
  queuedCount?: number;
  onAddInward?: () => void;
}

export function TopBar({
  warehouseName,
  isOnline = true,
  queuedCount = 0,
  onAddInward,
}: TopBarProps) {
  return (
    <header
      className="flex items-center justify-between px-4 border-b border-[var(--border-default)] bg-[var(--bg-surface)]"
      style={{ height: "var(--topbar-height)" }}
    >
      {/* Wordmark */}
      <div className="flex items-center gap-2">
        <Image src="/wordmark.svg" alt="StockRight" width={120} height={24} priority />
        {warehouseName && (
          <span className="text-[11px] font-mono uppercase tracking-widest text-[var(--text-tertiary)] hidden sm:block">
            {warehouseName}
          </span>
        )}
      </div>

      {/* Right: network status + CTA */}
      <div className="flex items-center gap-3">
        {isOnline && queuedCount === 0 ? (
          <Badge variant="online">● Online</Badge>
        ) : queuedCount > 0 ? (
          <Badge variant="offline">⚡ {queuedCount} queued</Badge>
        ) : (
          <Badge variant="offline">Offline</Badge>
        )}
        {onAddInward && (
          <Button size="sm" onClick={onAddInward} className="hidden sm:inline-flex">
            <Plus size={14} />
            Inward
          </Button>
        )}
      </div>
    </header>
  );
}
